package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    // Create a mock JsonElement that returns true for isJsonNull
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonNull()).thenReturn(true);
    // We need to make sure getAsJsonNull returns this casted to JsonNull.
    // Since we cannot cast mock to JsonNull, we stub getAsJsonNull to return a JsonNull mock.
    JsonNull jsonNull = mock(JsonNull.class);
    when(jsonElement.getAsJsonNull()).thenCallRealMethod();
    // Use a spy to override isJsonNull and getAsJsonNull behavior on a real JsonElement subclass
    JsonElement jsonElementSpy = new JsonElement() {
      @Override
      public boolean isJsonNull() {
        return true;
      }

      @Override
      public JsonElement deepCopy() {
        return this;
      }

      @Override
      public JsonNull getAsJsonNull() {
        if (isJsonNull()) {
          return (JsonNull) this;
        }
        throw new IllegalStateException("Not a JSON Null: " + this);
      }

      @Override
      public String toString() {
        return "mockJsonNull";
      }
    };

    // To avoid ClassCastException, we create a subclass of JsonNull instead of JsonElement
    JsonNull jsonNullSubclass = new JsonNull() {
      @Override
      public boolean isJsonNull() {
        return true;
      }
    };

    JsonNull result = jsonNullSubclass.getAsJsonNull();
    assertNotNull(result);
    assertSame(jsonNullSubclass, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    JsonElement jsonElement = new JsonElement() {
      @Override
      public boolean isJsonNull() {
        return false;
      }
      @Override
      public JsonElement deepCopy() {
        return null;
      }
      @Override
      public String toString() {
        return "notJsonNull";
      }
    };
    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonNull);
    assertTrue(exception.getMessage().startsWith("Not a JSON Null: "));
    assertTrue(exception.getMessage().contains(jsonElement.toString()));
  }
}
